index c55c40c88bc8..bbb1bb962233 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2170,8 +2170,21 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
   case Intrinsic::fshl:
   case Intrinsic::fshr: {
     Value *Op0 = II->getArgOperand(0), *Op1 = II->getArgOperand(1);
+    Value *ShAmt = II->getArgOperand(2);
     Type *Ty = II->getType();
     unsigned BitWidth = Ty->getScalarSizeInBits();
+
+    // fshl(X, 0, Y) --> shl X, Y
+    // fshl(X, undef, Y) --> shl X, Y
+    // This is valid when Y is known to be in [0, BitWidth).
+    if (IID == Intrinsic::fshl && (match(Op1, m_ZeroInt()) || match(Op1, m_Undef()))) {
+      // Check if the shift amount is known to be in valid range [0, BitWidth).
+      ConstantRange ShAmtRange =
+          computeConstantRangeIncludingKnownBits(ShAmt, /* IsSigned */ false, SQ);
+      if (ShAmtRange.getUpper().ule(BitWidth))
+        return BinaryOperator::CreateShl(Op0, ShAmt);
+    }
+
     Constant *ShAmtC;
     if (match(II->getArgOperand(2), m_ImmConstant(ShAmtC))) {
       // Canonicalize a shift amount constant operand to modulo the bit-width.
@@ -2205,11 +2218,6 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
       assert(IID == Intrinsic::fshl &&
              "All funnel shifts by simple constants should go left");

